#include "controller.h"
#include <stdio.h>
#include <stdlib.h>

void test_boot_leaves_pump_off() {
    controller_t controller;
    controller_init(&controller);

    /* Verify initial state is safe off */
    assert(controller.pump_on == false);
    assert(controller.state == CONTROLLER_STATE_SAFE_OFF);
}

void test_low_level_actuates_pump_on() {
    controller_t controller;
    controller_init(&controller);

    /* Send low level that should trigger pump ON */
    controller_step(&controller, (controller_input_t){
        .kind = CONTROLLER_INPUT_LEVEL,
        .level = 20,
        .now_ms = 1000,
    });

    /* Should be pumping */
    assert(controller.pump_on == true);
    assert(controller.state == CONTROLLER_STATE_PUMPING);
}

void test_high_level_stops_pump_off() {
    controller_t controller;
    controller_init(&controller);

    /* Pump ON, then send high level that should stop pump */
    controller_step(&controller, (controller_input_t){
        .kind = CONTROLLER_INPUT_LEVEL,
        .level = 20,
        .now_ms = 1000,
    });

    assert(controller.pump_on == true);
    assert(controller.state == CONTROLLER_STATE_PUMPING);

    controller_step(&controller, (controller_input_t){
        .kind = CONTROLLER_INPUT_LEVEL,
        .level = 85,
        .now_ms = 2000,
    });

    /* Should be off now */
    assert(controller.pump_on == false);
    assert(controller.state == CONTROLLER_STATE_SAFE_OFF);
}

void test_mid_level_preserves_output() {
    controller_t controller;
    controller_init(&controller);

    /* Pump ON at level 20, then hold at mid-level (50) */
    controller_step(&controller, (controller_input_t){
        .kind = CONTROLLER_INPUT_LEVEL,
        .level = 20,
        .now_ms = 1000,
    });

    assert(controller.pump_on == true);
    assert(controller.state == CONTROLLER_STATE_PUMPING);

    /* Hold at mid-level - should still be pumping */
    controller_step(&controller, (controller_input_t){
        .kind = CONTROLLER_INPUT_LEVEL,
        .level = 50,
        .now_ms = 2000,
    });

    assert(controller.pump_on == true);
    assert(controller.state == CONTROLLER_STATE_PUMPING);
}

void test_timeout_forces_off() {
    controller_t controller;
    controller_init(&controller);

    /* Send low level */
    controller_step(&controller, (controller_input_t){
        .kind = CONTROLLER_INPUT_LEVEL,
        .level = 20,
        .now_ms = 1000,
    });

    assert(controller.pump_on == true);

    /* Wait for timeout */
    usleep(10000); // 10ms delay, then wait longer than timeout

    /* Should be off due to timeout */
    assert(controller.pump_on == false);
    assert(controller.state == CONTROLLER_STATE_SAFE_OFF);
}

void test_malformed_input_forces_off() {
    controller_t controller;
    controller_init(&controller);

    /* Send low level */
    controller_step(&controller, (controller_input_t){
        .kind = CONTROLLER_INPUT_LEVEL,
        .level = 20,
        .now_ms = 1000,
    });

    assert(controller.pump_on == true);

    /* Send invalid level - should be off */
    controller_step(&controller, (controller_input_t){
        .kind = CONTROLLER_INPUT_INVALID_LEVEL,
        .level = -1,
        .now_ms = 2000,
    });

    assert(controller.pump_on == false);
    assert(controller.state == CONTROLLER_STATE_SAFE_OFF);
}

int main() {
    printf("Running controller tests...\n");

    test_boot_leaves_pump_off();
    printf("test_boot_leaves_pump_off: PASSED\n");

    test_low_level_actuates_pump_on();
    printf("test_low_level_actuates_pump_on: PASSED\n");

    test_high_level_stops_pump_off();
    printf("test_high_level_stops_pump_off: PASSED\n");

    test_mid_level_preserves_output();
    printf("test_mid_level_preserves_output: PASSED\n");

    test_timeout_forces_off();
    printf("test_timeout_forces_off: PASSED\n");

    test_malformed_input_forces_off();
    printf("test_malformed_input_forces_off: PASSED\n");

    printf("\nAll tests passed!\n");
    return 0;
}

